.box-demo {
  background-color: #e8f5e9;
  width: 300px;
  padding: 20px;
  border: 2px solid #2d6a4f;
  margin: 30px;
}

.card {
  width: 350px;
  padding: 24px;
  border: 1px solid #dddddd;
  border-radius: 12px;
  margin: 20px;
  background-color: #ffffff;
  font-family: "Noto Sans JP", sans-serif;
}

.card h2 {
  color: #2d6a4f;
  font-size: 20px;
  margin-top: 0;
  margin-bottom: 12px;
}

.card p {
  color: #555555;
  font-size: 14px;
  line-height: 1.8;
  margin: 0;
}
